class Solution {
public:
    int minimumScore(string s, string t) {
        int score = 0;
        int n = s.length();
        int m = t.length();

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (s[i] == t[j]) {
                    score += j + 1;
                }
            }
        }
        return score;
    }
};
